import React, { useState, useEffect } from 'react';
import axios from 'axios';
import './button.css';  // Import the CSS file for styling

const Button = ({ label = "Click Me", style = {} }) => {
  const [buttonStyle, setButtonStyle] = useState(style);  // Button's dynamic styles

  // Fetch button styles from the Figma API
  useEffect(() => {
    const fetchButtonStyles = async () => {
      try {
        const response = await axios.get('http://localhost:3001/figma-data');
        const figmaData = response.data;

        // Map Figma data to the button styles
        const newButtonStyle = {
          backgroundColor: figmaData.buttonColor || 'blue', // Default color if Figma data is missing
          padding: '12px 24px',
          borderRadius: '4px',
          fontSize: '14px',
          color: figmaData.textColor || 'white', // Figma text color
        };

        // Set the button style from Figma data
        setButtonStyle(newButtonStyle);
      } catch (error) {
        console.error('Error fetching Figma data:', error);
      }
    };

    // Call the function to fetch the button styles
    fetchButtonStyles();
  }, []);  // Only run once when the component mounts

  return (
    <button style={buttonStyle} className="button">
      {label}
    </button>
  );
};

export default Button;
